import json, os
from sklearn_crfsuite import CRF

from aliases import DataDict, DatasetFeatures, DatasetLabels, MorphList, DatasetMarginals, ConfidenceData
from partition import process_file
from db_worker import read_file, save_text
from process_data import process_data
from features import get_labeled_features, get_unlabeled_features
from model import build_crf, save_crf, load_crf
from evaluate import reconstruct_predictions, evaluate_predictions, get_confidence_data
from format import format_evaluation, format_increment

def run_training_cycle(config_json: str) -> str:
	"""
	Config contains:
		- annotatedFile: str
		- unannotatedFile: str
		- targetLanguage: str
		- method: str           Not currently implemented, but eventually will specify AL strategy (least confidence, random, etc.)
		- incrementSize: int
		- maxIterations: int
		- seed: int
		- delta: int

	Eventually, we want to move from the config containing the entire train, test, and select file content
	to only containing the file path, so we can just read from it.
	"""
	try:
		config: dict = json.loads(config_json)

		annotated_file: str = config['annotatedFile']
		unannotated_file: str = config['unannotatedFile']
		seed: int = config.get('seed', 42)

		target_language: str = config.get('targetLanguage', 'unknown')
		work_dir: str = f'/data/{target_language}/'

		train_file_path: str
		test_file_path: str
		train_file_path, test_file_path = process_file(work_dir, annotated_file, seed=seed)
		select_file_path: str = os.path.join(work_dir, unannotated_file)

		train_tgt: str = json.loads(read_file(train_file_path))['content']
		test_tgt: str = json.loads(read_file(test_file_path))['content']
		select_src: str = json.loads(read_file(select_file_path))['content']

		data: DataDict = process_data(train_tgt, test_tgt, select_src)

		X_train: DatasetFeatures
		y_train: DatasetLabels
		X_train, y_train = get_labeled_features(data['train']['words'], data['train']['bmes'], config['delta'])

		X_test: DatasetFeatures
		X_test, _ = get_labeled_features(data['test']['words'], data['test']['bmes'], config['delta'])

		crf: CRF = build_crf(X_train, y_train, config['maxIterations'])
		save_crf(crf, work_dir, 'crf.model')

		y_test_predict: DatasetLabels = crf.predict(X_test)
		test_predictions: list[MorphList] = reconstruct_predictions(y_test_predict, data['test']['words'])

		precision: float
		recall: float
		f1: float
		precision, recall, f1 = evaluate_predictions(data['test']['morphs'], test_predictions)
		evaluation_content: str = format_evaluation(
			data['test']['words'], data['test']['morphs'], test_predictions, precision, recall, f1
		)

		X_select = get_unlabeled_features(data['select']['words'], config['delta'])
		y_select_predict: DatasetLabels = crf.predict(X_select)
		marginals: DatasetMarginals = crf.predict_marginals(X_select)
		confidence_data: list[ConfidenceData] = get_confidence_data(data['select']['words'], y_select_predict, marginals)

		increment_words: list[str] = [word for word, _, _ in confidence_data[:config['incrementSize']]]
		increment_content: str = '\n'.join(increment_words)
		increment_data: str = format_increment(confidence_data[:config['incrementSize']])

		residual_words: list[str] = [word for word, _, _ in confidence_data[config['incrementSize']:]]
		residual_count: int = len(residual_words)
		residual_content: str = '\n'.join(residual_words)

		return json.dumps({
			'precision': precision,
			'recall': recall,
			'f1': f1,
			'incrementWords': increment_data,
			'residualCount': residual_count,
			'incrementContent': increment_content,
			'residualContent': residual_content,
			'evaluationContent': evaluation_content,
			'error': None,
		})
	except Exception:
		import traceback
		return json.dumps({
            'precision': 0.0,
            'recall': 0.0,
            'f1': 0.0,
            'incrementWords': [],
            'residualCount': 0,
            'incrementContent': '',
            'residualContent': '',
            'evaluationContent': '',
            'error': traceback.format_exc(),
        })
	
def run_inference(config_json: str) -> str:
	"""
    Run the trained CRF model over residual words without retraining.
    Loads crf.model from the VFS written during the last training cycle.

    :param config_json: JSON string with fields:
        - residualTgt: str   residual pool content (.tgt format)
        - delta: int         context window for features (default 4)
        - workDir: str       VFS directory where crf.model lives
    :type config_json: str
    :return: JSON string with fields:
        - predictions: list[{word, segmentation}]
        - predictionsContent: str   full .tgt file content for download
        - totalWords: int
        - error: str | null
    :rtype: str
    """
	try:
		config: dict = json.loads(config_json)

		target_language: str = config.get('targetLanguage', 'unknown')
		work_dir: str = f'data/{target_language}/'
		delta: int = config.get('delta', 4)

		crf: CRF | None = load_crf(work_dir, 'crf.model')
		if crf is None:
			return json.dumps({
                'predictionsContent': '',
                'totalWords': 0,
                'error': 'No trained model found. Run at least one training cycle first.'
			})
		
		residual_content = config.get('residualTgt', '')
		if not residual_content.strip():
			return json.dumps({
                'predictionsContent': '',
                'totalWords': 0,
                'error': None
            })
		
		words: list[str] = [
			line.strip().replace('!', '')
			for line in residual_content.splitlines()
			if line.strip()
		]

		X_select: DatasetFeatures = get_unlabeled_features(words, delta)
		y_predict: DatasetLabels = crf.predict(X_select)
		predicted_morphs: list[MorphList] = reconstruct_predictions(y_predict, words)

		tgt_lines: list[str] = ['!'.join(morphs) for morphs in predicted_morphs]
		predictions_content: str = '\n'.join(tgt_lines) + '\n'

		return json.dumps({
            'predictionsContent': predictions_content,
            'totalWords': len(words),
            'error': None
        })

	except Exception:
		import traceback
		return json.dumps({
			'predictionsContent': '',
            'totalWords': 0,
            'error': traceback.format_exc()
		})